import { shallowRef, watch } from 'vue';
import { getTableColumnKey, isTableGroupColumn } from '@soybeanjs/headless/table';
import { useTable as _useTable } from '@soybeanjs/hooks';
import type { UseTableOptions as _UseTableOptions, TableColumnCheck } from '@soybeanjs/hooks';
import type { TableBaseData, TableColumn, TableColumnType } from './types';

export type UseTableOptions<ResponseData, ApiData extends TableBaseData, Pagination extends boolean> = Omit<
  _UseTableOptions<ResponseData, ApiData, TableColumn<ApiData>, Pagination>,
  'pagination' | 'getColumnChecks' | 'getColumns'
>;

export function useTable<ResponseData, ApiData extends TableBaseData>(
  options: UseTableOptions<ResponseData, ApiData, false>
) {
  const result = _useTable<ResponseData, ApiData, TableColumn<ApiData>, false>({
    ...options,
    getColumnChecks,
    getColumns
  });

  return result;
}

export type UsePaginatedTableOptions<ResponseData, ApiData extends TableBaseData> = UseTableOptions<
  ResponseData,
  ApiData,
  true
> & {
  page?: number;
  pageSize?: number;
  /**
   * Whether to fetch data when page or pageSize changes.
   *
   * Set this to `false` if you want to handle pagination change manually, such as fetching data in a parent component.
   *
   * In this case, you can listen to `update:page` and `update:pageSize` events to get the current page and page size.
   *
   * @default true
   */
  fetchOnPaginationChange?: boolean;
};

export function usePaginatedTable<ResponseData, ApiData extends TableBaseData>(
  options: UsePaginatedTableOptions<ResponseData, ApiData>
) {
  const { page: _page = 1, pageSize: _pageSize = 10, fetchOnPaginationChange = true, onFetched } = options;

  const page = shallowRef(_page);
  const pageSize = shallowRef(_pageSize);
  const total = shallowRef(0);

  const result = _useTable<ResponseData, ApiData, TableColumn<ApiData>, true>({
    ...options,
    pagination: true,
    getColumnChecks,
    getColumns,
    onFetched: data => {
      if (data.total && data.total !== total.value) {
        total.value = data.total;
      }
      if (data.page && data.page !== page.value) {
        page.value = data.page;
      }
      if (data.pageSize && data.pageSize !== pageSize.value) {
        pageSize.value = data.pageSize;
      }

      onFetched?.(data);
    }
  });

  watch(
    [page, pageSize],
    () => {
      if (fetchOnPaginationChange) {
        result.fetchData();
      }
    },
    { flush: 'post' }
  );

  return {
    page,
    pageSize,
    total,
    ...result
  };
}

function getColumnChecks<T extends TableColumn<any>>(columns: T[]) {
  const cols: TableColumnCheck[] = [];

  columns.forEach(col => {
    if (isTableGroupColumn(col)) {
      cols.push(...getColumnChecks(col.children));
      return;
    }

    const { type, title, hidden } = col;

    // Group columns are flattened above, so only leaf data columns participate in visibility checks.
    if (type || !col.dataIndex) return;

    const key = getTableColumnKey(col);

    const column: TableColumnCheck = {
      key,
      title: title || key,
      checked: true,
      hidden
    };

    cols.push(column);
  });

  return cols;
}

function getColumns<T extends TableColumn<any>>(columns: T[], checks: TableColumnCheck[]) {
  const typeColumnsMap = new Map<TableColumnType, { column: T; index: number }>();
  const checksMap = new Map(checks.map(check => [check.key, check]));
  const checksOrderMap = new Map(checks.map((check, i) => [check.key, i]));

  columns.forEach((column, index) => {
    if (column.type) {
      typeColumnsMap.set(column.type, { column, index });
    }
  });

  function getMinCheckOrder(column: TableColumn<any>): number {
    if (isTableGroupColumn(column)) {
      const childOrders = column.children.map(child => getMinCheckOrder(child));
      return childOrders.length > 0 ? Math.min(...childOrders) : Infinity;
    }
    return checksOrderMap.get(getTableColumnKey(column)) ?? Infinity;
  }

  const nonTypeColumns = columns.filter(col => !col.type);
  const sortedNonType = [...nonTypeColumns].sort((a, b) => getMinCheckOrder(a) - getMinCheckOrder(b));

  const result = sortedNonType.reduce<T[]>((acc, column) => {
    if (isTableGroupColumn(column)) {
      const nextChildren = getColumns(column.children, checks);

      if (nextChildren.length > 0) {
        acc.push({ ...column, children: nextChildren });
      }

      return acc;
    }

    const check = checksMap.get(getTableColumnKey(column));

    if (check?.checked !== false) {
      acc.push(column);
    }

    return acc;
  }, []);

  typeColumnsMap.forEach(({ column, index }) => {
    if (index >= result.length) {
      result.push(column);
    } else {
      result.splice(index, 0, column);
    }
  });

  return result;
}

export { default as STable } from './table.vue';
export { TableRow as STableRow, TableCell as STableCell } from '@soybeanjs/headless/table';
export { useTable, usePaginatedTable } from './hooks';

export type * from '@soybeanjs/headless/table';
export type { TableColumnCheck } from '@soybeanjs/hooks';
export type * from './types';

import type {
  TableBaseData,
  TableColumn,
  TableColumnFilter,
  TableColumnFilterOption,
  TableColumnFilterValue,
  TableColumnType,
  TableCompactProps,
  TableCompactEmits,
  TableCompactSlots,
  TableHeaderFilterSlotProps,
  TableUnifiedKey,
  TableSortOrder,
  TableUiSlot
} from '@soybeanjs/headless/table';
import type { ClassValue, UiClass } from '@soybeanjs/headless/types';
import type { TableVariant } from '@/styles/table';
import type { ThemeSize } from '@/theme';

/**
 * Additional UI slots for the table component.
 */
export type TableExtraUiSlot =
  | 'selection'
  | 'filterTrigger'
  | 'filterPopup'
  | 'filterSearch'
  | 'filterOptions'
  | 'filterOption'
  | 'filterOptionLabel'
  | 'filterFooter'
  | 'filterCount'
  | 'filterAction'
  | 'filterEmpty';

/**
 * Extended UI class overrides for the Table component.
 */
export type TableExtendedUi = UiClass<TableUiSlot | TableExtraUiSlot>;

/**
 * Properties for the Table component.
 */
export interface TableProps<
  T extends TableBaseData = TableBaseData,
  R extends string | number = string | number,
  M extends boolean = false
> extends TableCompactProps<T, R, M> {
  /**
   * Additional class names to apply to the table.
   */
  class?: ClassValue;
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
  /**
   * Per-slot class overrides for the component.
   */
  ui?: Partial<TableExtendedUi>;
  /**
   * Visual variant of the component.
   */
  variant?: TableVariant;
  /**
   * Whether bordered.
   */
  bordered?: boolean;
  /**
   * Whether rounded.
   */
  rounded?: boolean;
  /**
   * Whether striped.
   */
  striped?: boolean;
}

/**
 * Events for the Table component.
 */
export type TableEmits<
  T extends TableBaseData = TableBaseData,
  R extends TableUnifiedKey = TableUnifiedKey,
  M extends boolean = false
> = TableCompactEmits<T, R, M>;

/**
 * Slots for the Table component.
 */
export type TableSlots<T extends TableBaseData = TableBaseData> = TableCompactSlots<T>;

/**
 * Properties for the TableRadio component.
 */
export interface TableRadioProps {
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
  /**
   * Whether the item is checked.
   */
  checked?: boolean;
}

/**
 * Type information for TableFilterPopoverColumnMeta.
 */
export interface TableFilterPopoverColumnMeta {
  /**
   * Title text rendered by the component.
   */
  title?: string;
  /**
   * Key.
   */
  key?: string;
  /**
   * Data index.
   */
  dataIndex?: string;
}

/**
 * Type information for TableFilterPopoverOption.
 */
export interface TableFilterPopoverOption {
  /**
   * Label text rendered by the component.
   */
  label: string;
  /**
   * Value associated with the current item.
   */
  value: string;
  /**
   * Whether the component is disabled.
   */
  disabled?: boolean;
}

/**
 * Properties for the TableFilterPopover component.
 */
export interface TableFilterPopoverProps<
  T extends TableBaseData = TableBaseData
> extends TableHeaderFilterSlotProps<T> {
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
  /**
   * Per-slot class overrides for the component.
   */
  ui: TableExtendedUi;
}

export type {
  TableBaseData,
  TableColumn,
  TableColumnFilter,
  TableColumnFilterOption,
  TableColumnFilterValue,
  TableColumnType,
  TableSortOrder
};

